INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('SUP_CONTENT: Le content-channel fit matrix: Reels=decouverte(nouveau public), Stories=engagement(audience existante), Posts=SEO social, Lives=conversion, DMs=closing.', 'Content-channel fit: Reels decouverte, Stories engagement, Posts SEO, Lives conversion, DMs closing', 'content', 'best_practice', 0.90, 'supreme', 'system'),
('SUP_CONTENT: Le visual hierarchy in posts: 1) image/video qui arrete le scroll, 2) texte overlay qui resume le message, 3) caption qui developpe, 4) CTA en dernier.', 'Visual hierarchy: image arret → texte overlay → caption → CTA', 'content', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_CONTENT: Le content fatigue detection: si l engagement baisse de 30%+ sur 2 semaines consecutives, changer de format ou de sujet. L audience s ennuie.', 'Content fatigue: engagement -30% 2 sem = changer format/sujet', 'content', 'insight', 0.85, 'supreme', 'system'),
('SUP_CONTENT: Le evergreen vs trending ratio: 60% evergreen (durable) + 40% trending (actuel). L evergreen genere du trafic sur 2-3 ans, le trending pour 48h.', 'Evergreen 60% + trending 40%. Evergreen = 2-3 ans, trending = 48h', 'content', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_CONTENT: Le UGC amplification: quand un client publie sur votre produit, repost + commentaire + DM remerciement. Le client se sent valorise et repartage.', 'UGC amplification: repost + commentaire + DM merci = client repartage', 'content', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_COMMERCIAL: Le discovery call scoring: noter chaque call 1-5 sur: budget(B), autorite(A), besoin(N), timeline(T). Score BANT > 15 = deal qualifie.', 'Discovery scoring BANT: B+A+N+T sur 5. Total > 15 = qualifie', 'commercial', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_COMMERCIAL: Le objection library: documenter chaque objection entendue + la meilleure reponse testee. Apres 50 objections, on a 95% des cas couverts.', 'Objection library: documenter + meilleure reponse. 50 objections = 95% cas couverts', 'commercial', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_COMMERCIAL: Le commitment escalation: petit engagement (newsletter) → moyen (demo) → grand (pilot) → tres grand (contrat). Chaque etape prepare la suivante.', 'Commitment escalation: newsletter → demo → pilot → contrat. Chaque prepare suivante', 'commercial', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_COMMERCIAL: Le post-sale handoff checklist: transmettre au CS: objectifs client, problemes identifies, timeline attendue, contacts cles, promesses faites.', 'Post-sale handoff: objectifs + problemes + timeline + contacts + promesses', 'commercial', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_COMMERCIAL: Le win rate by stage analysis: mesurer le taux de conversion entre chaque etape du pipeline. L etape avec le plus de drop = le point a fixer.', 'Win rate par stage: etape max drop = point a fixer en priorite', 'commercial', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_EMAIL: Le email personalization depth levels: L1=prenom, L2=entreprise/secteur, L3=comportement recent, L4=historique complet, L5=predictif. Viser L3 minimum.', 'Perso email 5 niveaux: prenom → entreprise → comportement → historique → predictif. Min L3', 'email', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_EMAIL: Le email testing roadmap: mois 1=subject lines, mois 2=send times, mois 3=content format, mois 4=CTAs, mois 5=segmentation, mois 6=automation triggers.', 'Testing roadmap email: M1 subjects, M2 times, M3 format, M4 CTAs, M5 segment, M6 triggers', 'email', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_EMAIL: Le compliance checklist: SPF+DKIM+DMARC configures, lien desinscription visible, adresse physique presente, consentement opt-in documente.', 'Compliance email: SPF+DKIM+DMARC + unsub + adresse + opt-in documente', 'email', 'best_practice', 0.90, 'supreme', 'system'),
('SUP_EMAIL: Le revenue per subscriber (RPS): revenu total email / nombre abonnes. Optimiser le RPS est plus important que d agrandir la liste.', 'RPS = revenu/abonnes. Optimiser RPS > agrandir liste', 'email', 'insight', 0.85, 'supreme', 'system'),
('SUP_EMAIL: Le email lifecycle value: welcome series (5-10% du revenu email) + nurturing (15-20%) + promotional (40-50%) + triggered (25-30%). Equilibrer.', 'Email lifecycle revenue: welcome 5-10%, nurture 15-20%, promo 40-50%, triggered 25-30%', 'email', 'insight', 0.82, 'supreme', 'system'),
('SUP_SEO: Le SERP volatility monitoring: si les positions fluctuent de +/-5 positions en 7 jours, c est un signe de mise a jour algorithmique. Attendre avant de reagir.', 'SERP volatility +/-5 positions 7j = update algo. Attendre avant reagir', 'seo', 'insight', 0.82, 'supreme', 'system'),
('SUP_SEO: Le content consolidation: fusionner 2-3 articles faibles sur le meme sujet en 1 article complet et rediriger les anciens URLs en 301. +40% traffic.', 'Content consolidation: fusionner articles faibles → 1 complet + 301 = +40% traffic', 'seo', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_SEO: Le search demand forecasting: utiliser Google Trends + historique pour predire les pics de demande et preparer le contenu 4-6 semaines avant.', 'Search demand forecasting: Trends + historique = preparer contenu 4-6 sem avant pic', 'seo', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_SEO: Le brand SERP optimization: quand quelqu un Google votre marque, la 1ere page doit afficher: site, social profiles, avis, articles de presse, Wikipedia.', 'Brand SERP: site + social + avis + presse + Wikipedia en page 1', 'seo', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_SEO: Le page-level TF-IDF analysis: analyser la densite des termes importants dans les pages #1 et ajuster votre contenu pour correspondre au profil semantique.', 'TF-IDF page-level: correspondre profil semantique pages #1', 'seo', 'best_practice', 0.80, 'supreme', 'system'),
('SUP_ADS: Le creative psychology framework: 1) arreter le scroll (visuel), 2) creer l emotion (probleme/desir), 3) presenter la solution, 4) prouver (social proof), 5) urger (CTA).', 'Creative psychology: arret scroll → emotion → solution → preuve → urgence', 'ads', 'best_practice', 0.88, 'supreme', 'system'),
('SUP_ADS: Le ad account structure: 1 campagne par objectif (awareness/consideration/conversion), 1-3 ad sets par audience, 3-5 ads par ad set. Simple et testable.', 'Account structure: 1 campagne/objectif, 1-3 ad sets/audience, 3-5 ads/ad set', 'ads', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_ADS: Le diminishing returns detection: quand doubler le budget n augmente le ROAS que de 10%, on atteint le plafond de l audience. Trouver de nouvelles audiences.', 'Diminishing returns: 2x budget = +10% ROAS → plafond audience. Nouvelles audiences', 'ads', 'insight', 0.82, 'supreme', 'system'),
('SUP_ADS: Le seasonal budget planning: Q1 CPMs bas (-20%), Q2-Q3 normal, Q4 CPMs hauts (+50-100%). Ajuster le budget et les objectifs par trimestre.', 'Budget saisonnier: Q1 -20% CPM, Q2-3 normal, Q4 +50-100%. Ajuster', 'ads', 'insight', 0.82, 'supreme', 'system'),
('SUP_ADS: Le creative scorecard: noter chaque creative 1-5 sur hook rate, CTR, conversion rate, ROAS. Score > 15 = winner a scaler.', 'Creative scorecard: hook+CTR+conv+ROAS sur 5. >15 = scaler', 'ads', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_CEO: Le agent efficiency metric: resultats obtenus / cout API consomme. Chaque agent doit avoir un ROI positif mesurable.', 'Agent efficiency: resultats / cout API. ROI positif obligatoire', 'ceo', 'best_practice', 0.88, 'supreme', 'system'),
('SUP_CEO: Le strategic alignment check: chaque semaine verifier que les actions des agents sont alignees avec l objectif #1 du client.', 'Alignment check hebdo: actions agents alignees objectif #1 client', 'ceo', 'best_practice', 0.88, 'supreme', 'system'),
('SUP_CEO: Le escalation protocol: anomalie detectee → alerter client si impact > 10% du CA. Ne pas alerter pour des micro-variations.', 'Escalation: impact > 10% CA → alerter client. Micro-variations = ignorer', 'ceo', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_CEO: Le quarterly business review: presenter au client: resultats vs objectifs, ROI de chaque agent, recommandations prochains 90 jours.', 'QBR client: resultats vs objectifs + ROI agents + reco 90 jours', 'ceo', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_CEO: Le competitive intelligence sharing: quand un concurrent lance une nouvelle feature ou campagne, informer le client et proposer une reponse strategique.', 'Competitive intelligence: concurrent nouvelle feature/campagne → informer + reponse', 'ceo', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_RETENTION: Le time-to-value acceleration: chaque jour de retard dans la realisation de la valeur augmente le risque de churn de 5%.', 'TTV acceleration: +1 jour retard valeur = +5% risque churn', 'retention', 'insight', 0.85, 'supreme', 'system'),
('SUP_RETENTION: Le feature discovery prompts: afficher des tooltips pour les features non-decouvertes quand le client est pret (pas pendant l onboarding).', 'Feature discovery: tooltips features non-decouvertes quand client pret', 'retention', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_RETENTION: Le success plan per customer: documenter les objectifs du client, les jalons, les metriques de succes. Revoir trimestriellement.', 'Success plan par client: objectifs + jalons + metriques. Revoir trimestriel', 'retention', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_RETENTION: Le advocacy program: NPS 9-10 → proposer temoignage (reduction), referral (mois gratuit), beta test (acces anticipe), advisory board (influence).', 'Advocacy NPS 9-10: temoignage + referral + beta + advisory board', 'retention', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_ONBOARDING: Le onboarding personalization by segment: restaurant → montrer contenu food, coach → montrer contenu coaching, ecommerce → montrer produit. Pas generique.', 'Onboarding personnalise par segment: restaurant/coach/ecom → contenu adapte', 'onboarding', 'best_practice', 0.88, 'supreme', 'system'),
('SUP_ONBOARDING: Le progress gamification: barre de completion + confettis a chaque etape + badge a la fin. Les utilisateurs qui completent l onboarding restent 5x plus.', 'Gamification onboarding: barre + confettis + badge. Completion = 5x retention', 'onboarding', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_DM: Le DM qualification framework: engagement level (likes/comments history) + profile quality (bio complete, posts recents) + business fit (secteur/taille). Score 1-10.', 'DM qualification: engagement + profil + business fit. Score 1-10', 'dm_instagram', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_DM: Le DM template library: 5 templates par etape (intro, follow-up, valeur, question, closing) × par segment (restaurant, coach, boutique). 75 templates total.', 'DM templates: 5 par etape × par segment = 75 templates', 'dm_instagram', 'best_practice', 0.82, 'supreme', 'system'),
('SUP_WHATSAPP: Le WhatsApp automation safe limits: max 3 messages/conversation/jour, max 1 promo/semaine, toujours option opt-out, respecter fenetre 24h.', 'WhatsApp safe: 3 msg/conv/jour, 1 promo/sem, opt-out, fenetre 24h', 'whatsapp', 'best_practice', 0.88, 'supreme', 'system'),
('SUP_CHATBOT: Le chatbot performance optimization: tracker les top 10 questions sans reponse, les ajouter a la base. En 30 jours, le taux de resolution passe de 60% a 85%.', 'Chatbot optim: tracker top 10 sans reponse → ajouter. 60% → 85% en 30j', 'chatbot', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_GMAPS: Le local ranking boost strategy: 10 nouveaux avis/mois + 4 Google Posts/mois + 10 nouvelles photos/mois + reponses < 24h = top 3 pack local.', 'GMaps boost: 10 avis + 4 posts + 10 photos + reponses < 24h/mois = top 3', 'gmaps', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_TIKTOK: Le TikTok growth compound: chaque video virale amene des followers, qui augmentent la baseline view des prochaines videos. L effet compose.', 'TikTok compound: virale → followers → baseline views augmentee. Effet compose', 'tiktok_comments', 'insight', 0.82, 'supreme', 'system'),
('SUP_COMPTABLE: Le financial alert system: MRR growth < 5% → jaune. Churn > 5% → rouge. Runway < 4 mois → rouge. LTV/CAC < 2 → jaune. Gross margin < 65% → rouge.', 'Financial alerts: MRR<5% jaune, churn>5% rouge, runway<4m rouge, LTV/CAC<2 jaune, margin<65% rouge', 'comptable', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_RH: Le hiring pipeline metrics: applications → screen → interview → assessment → offer → accept. Mesurer le taux de conversion et le temps a chaque etape.', 'Hiring pipeline: app → screen → interview → assess → offer → accept. Conv + temps', 'rh', 'best_practice', 0.80, 'supreme', 'system'),
('SUP_MARKETING: Le campaign planning template: objectif (SMART) → audience cible → message cle → canaux → budget → timeline → KPIs → post-mortem.', 'Campaign planning: objectif SMART → audience → message → canaux → budget → timeline → KPIs → post-mortem', 'marketing', 'best_practice', 0.85, 'supreme', 'system'),
('SUP_CROSS: Le agent collaboration matrix: content cree → SEO optimise → ads amplifie → email distribue → commercial close → retention garde → CEO supervise.', 'Agent collab: content → SEO → ads → email → commercial → retention → CEO', NULL, 'best_practice', 0.90, 'supreme', 'system'),
('SUP_CROSS: Le real-time signal routing: email ouvert → DM agent engage. Pricing visite → commercial alerte. Avis negatif → retention intervient. Trend detecte → content cree.', 'Signal routing: email→DM, pricing→commercial, avis negatif→retention, trend→content', NULL, 'best_practice', 0.88, 'supreme', 'system'),
('SUP_CROSS: Le unified customer timeline: chaque interaction (email, DM, appel, ticket, achat, login) visible dans 1 timeline chronologique. Vision 360° du client.', 'Unified timeline: toutes interactions en 1 timeline chrono. Vision 360°', NULL, 'best_practice', 0.88, 'supreme', 'system'),
('SUP_CROSS: Le inter-agent learning loop: quand 1 agent decouvre un insight (ex: les restaurants repondent mieux le mardi), TOUS les agents adaptent leur timing.', 'Inter-agent learning: insight 1 agent → tous adaptent. Ex: restaurants mardi', NULL, 'best_practice', 0.88, 'supreme', 'system'),
('SUP_KEIROAI: Le KeiroAI north star: nombre d actions reussies par agent par semaine par client. Si ce chiffre augmente, tout le reste suit.', 'North star KeiroAI: actions reussies / agent / semaine / client', 'ceo', 'best_practice', 0.92, 'supreme', 'system')
